336→// ---------------------------------------------------------------------------
337→// Update text (for edit-and-approve)
338→// ---------------------------------------------------------------------------
339→
340→export async function updateLearningText(input: {
341→  surreal: Surreal;
342→  learningRecord: LearningRecord;
343→  newText: string;
344→  now: Date;
345→}): Promise<void> {
346→  await input.surreal.update(input.learningRecord).merge({
347→    text: input.newText,
348→    updated_at: input.now,
349→  });
350→}
