  1→/**
  2→ * Pattern Detection Module
  3→ *
  4→ * Rate limiting gate and dismissed re-suggestion prevention for agent-suggested learnings.
  5→ * Pure functions that compose query results into blocking/allow decisions.
  6→ */
  7→import { RecordId, type Surreal } from "surrealdb";
  8→import { countRecentSuggestionsByAgent, createLearning } from "./queries";
  9→import type { CreateLearningInput, LearningRecord } from "./types";
 10→
 11→// ---------------------------------------------------------------------------
 12→// Result types
 13→// ---------------------------------------------------------------------------
 14→
 15→export type RateLimitResult =
 16→  | { blocked: false; count: number }
 17→  | { blocked: true; count: number };
 18→
 19→export type DismissedSimilarityResult =
 20→  | { blocked: false }
 21→  | { blocked: true; matchedText: string };
 22→
 23→export type SuggestLearningResult =
 24→  | { created: true; learningRecord: LearningRecord }
 25→  | { created: false; reason: "rate_limited"; count: number }
 26→  | { created: false; reason: "dismissed_similarity"; matchedText: string };
 27→
 28→// ---------------------------------------------------------------------------
 29→// Rate limit check
 30→// ---------------------------------------------------------------------------
 31→
 32→const RATE_LIMIT_MAX = 5;
 33→
 34→export async function checkRateLimit(input: {
 35→  surreal: Surreal;
 36→  workspaceRecord: RecordId<"workspace", string>;
 37→  agentType: string;
 38→}): Promise<RateLimitResult> {
 39→  const count = await countRecentSuggestionsByAgent({
 40→    surreal: input.surreal,
 41→    workspaceRecord: input.workspaceRecord,
 42→    agentType: input.agentType,
 43→  });
 44→
 45→  return count >= RATE_LIMIT_MAX
 46→    ? { blocked: true, count }
 47→    : { blocked: false, count };
 48→}
 49→
 50→// ---------------------------------------------------------------------------
 51→// Dismissed similarity check (KNN two-step pattern)
 52→// ---------------------------------------------------------------------------
 53→
 54→// Higher than collision thresholds (0.75 learning, 0.40 policy, 0.55 decision)
 55→// because dismissed re-suggestion must be near-identical to the original --
 56→// a slightly different learning on the same topic should still be allowed.
 57→const DISMISSED_SIMILARITY_THRESHOLD = 0.85;
 58→
 59→export async function checkDismissedSimilarity(input: {
 60→  surreal: Surreal;
 61→  workspaceRecord: RecordId<"workspace", string>;
 62→  proposedEmbedding: number[];
 63→}): Promise<DismissedSimilarityResult> {
 64→  // Step 1: KNN candidates (HNSW index only)
 65→  // Step 2: Filter by workspace + dismissed status + similarity threshold
 66→  const [matches] = await input.surreal
 67→    .query<[Array<{ text: string; similarity: number }>]>(
 68→      [
 69→        "LET $candidates = SELECT id, text, workspace, status,",
 70→        "vector::similarity::cosine(embedding, $embedding) AS similarity",
 71→        "FROM learning WHERE embedding <|10, COSINE|> $embedding;",
 72→        "SELECT text, similarity FROM $candidates",
 73→        `WHERE workspace = $ws AND status = "dismissed" AND similarity > ${DISMISSED_SIMILARITY_THRESHOLD}`,
 74→        "ORDER BY similarity DESC LIMIT 1;",
 75→      ].join("\n"),
 76→      {
 77→        embedding: input.proposedEmbedding,
 78→        ws: input.workspaceRecord,
 79→      },
 80→    )
 81→    .collect<[Array<{ text: string; similarity: number }>]>();
 82→
 83→  const match = matches[0];
 84→  if (match) {
 85→    return { blocked: true, matchedText: match.text };
 86→  }
 87→  return { blocked: false };
 88→}
 89→
 90→// ---------------------------------------------------------------------------
 91→// Suggest learning (orchestrates gates then creates)
 92→// ---------------------------------------------------------------------------
 93→
 94→export async function suggestLearning(input: {
 95→  surreal: Surreal;
 96→  workspaceRecord: RecordId<"workspace", string>;
 97→  learning: CreateLearningInput;
 98→  embedding?: number[];
 99→  now: Date;
100→}): Promise<SuggestLearningResult> {
101→  const agentType = input.learning.suggestedBy ?? "unknown_agent";
102→
103→  // Gate 1: Rate limit
104→  const rateLimit = await checkRateLimit({
105→    surreal: input.surreal,
106→    workspaceRecord: input.workspaceRecord,
107→    agentType,
108→  });
109→
110→  if (rateLimit.blocked) {
111→    return { created: false, reason: "rate_limited", count: rateLimit.count };
112→  }
113→
114→  // Gate 2: Dismissed similarity (only when embedding available)
115→  if (input.embedding) {
116→    const dismissed = await checkDismissedSimilarity({
117→      surreal: input.surreal,
118→      workspaceRecord: input.workspaceRecord,
119→      proposedEmbedding: input.embedding,
120→    });
121→
122→    if (dismissed.blocked) {
123→      return {
124→        created: false,
125→        reason: "dismissed_similarity",
126→        matchedText: dismissed.matchedText,
127→      };
128→    }
129→  }
130→
131→  // Both gates passed -- create learning as pending_approval
132→  const learningRecord = await createLearning({
133→    surreal: input.surreal,
134→    workspaceRecord: input.workspaceRecord,
135→    learning: {
136→      ...input.learning,
137→      source: "agent",
138→    },
139→    now: input.now,
140→    embedding: input.embedding,
141→  });
142→
143→  return { created: true, learningRecord };
144→}
