473→/**
474→ * Generates real embedding vectors using the configured embedding model.
475→ * Returns a map of text -> embedding for seeding test data with real vectors.
476→ */
477→export async function generateEmbeddings(
478→  texts: string[],
479→): Promise<Map<string, number[]>> {
480→  const { embeddings } = await embedMany({
481→    model: testAI.embeddingModel,
482→    values: texts,
483→  });
484→  const result = new Map<string, number[]>();
485→  for (let i = 0; i < texts.length; i++) {
486→    result.set(texts[i], embeddings[i]);
487→  }
488→  return result;
489→}
