 13→async function executeEntityAction(
 14→  workspaceId: string,
 15→  entityId: string,
 16→  action: string,
 17→): Promise<void> {
 18→  const response = await fetch(
 19→    `/api/entities/${encodeURIComponent(entityId)}/actions?workspaceId=${encodeURIComponent(workspaceId)}`,
 20→    {
 21→      method: "POST",
 22→      headers: { "Content-Type": "application/json" },
 23→      body: JSON.stringify({ action }),
