 32→export function GovernanceFeed({
 33→  feed,
 34→  isLoading,
 35→  error,
 36→  onRefresh,
 37→}: {
 38→  feed: GovernanceFeedResponse | undefined;
 39→  isLoading: boolean;
 40→  error: string | undefined;
 41→  onRefresh: () => void;
 42→}) {
 43→  const workspaceId = useWorkspaceState((s) => s.workspaceId);
 44→  const navigateToDiscussEntity = useViewState((s) => s.navigateToDiscussEntity);
 45→  const navigate = useNavigate();
 46→
 47→  async function handleAction(item: GovernanceFeedItem, action: GovernanceFeedAction) {
 48→    if (!workspaceId) return;
 49→
 50→    const classification = classifyFeedAction(item, action);
 51→
 52→    switch (classification.type) {
 53→      case "navigate_discuss":
 54→        navigateToDiscussEntity({
 55→          id: item.entityId,
 56→          kind: item.entityKind,
 57→          name: item.entityName,
 58→          ...(item.status ? { status: item.status } : {}),
 59→        });
 60→        void navigate({ to: "/chat" });
 61→        return;
 62→
 63→      case "navigate_review":
 64→        void navigate({ to: `/review/${classification.sessionId}` as string });
 65→        return;
 66→
 67→      case "abort_session":
 68→        await abortSession(workspaceId, classification.sessionId);
 69→        onRefresh();
 70→        return;
 71→
 72→      case "entity_action":
 73→        await executeEntityAction(workspaceId, item.entityId, action.action);
 74→        onRefresh();
 75→        return;
 76→    }
 77→  }
 78→
 79→  if (error) {
 80→    return (
 81→      <div className="feed-error">
 82→        <p>{error}</p>
 83→        <button type="button" onClick={onRefresh}>Retry</button>
 84→      </div>
 85→    );
 86→  }
 87→
 88→  if (!feed && isLoading) {
 89→    return <p className="feed-loading">Loading governance feed...</p>;
 90→  }
 91→
 92→  if (!feed) return undefined;
 93→
 94→  const totalItems = feed.blocking.length + feed.review.length + feed.awareness.length;
 95→
 96→  if (totalItems === 0) {
 97→    return (
 98→      <div className="feed-empty">
 99→        <p>No governance items require attention.</p>
100→      </div>
101→    );
102→  }
103→
104→  return (
105→    <div className="governance-feed">
106→      <FeedSection tier="blocking" items={feed.blocking} onAction={handleAction} />
107→      <FeedSection tier="review" items={feed.review} onAction={handleAction} />
108→      <FeedSection tier="awareness" items={feed.awareness} onAction={handleAction} />
109→    </div>
110→  );
111→}
