247→export async function collectSseEvents<T extends { type: string }>(streamUrl: string, timeoutMs: number): Promise<T[]> {
248→  const response = await fetch(streamUrl, { headers: { Accept: "text/event-stream" } });
249→  if (!response.ok || !response.body) {
250→    throw new Error(`Failed to open SSE stream (${response.status})`);
251→  }
252→
253→  const reader = response.body.getReader();
254→  const decoder = new TextDecoder();
255→  const events: T[] = [];
256→  let buffer = "";
257→
258→  const timeout = setTimeout(() => {
259→    void reader.cancel();
260→  }, timeoutMs);
261→
262→  try {
263→    while (true) {
264→      const { value, done } = await reader.read();
265→      if (done) {
266→        break;
267→      }
268→
269→      buffer += decoder.decode(value, { stream: true });
270→      const segments = buffer.split("\n\n");
271→      buffer = segments.pop() ?? "";
272→
273→      for (const segment of segments) {
274→        const dataLine = segment.split("\n").find((line) => line.startsWith("data: "));
275→        if (!dataLine) {
276→          continue;
277→        }
278→
279→        const event = JSON.parse(dataLine.slice("data: ".length)) as T;
280→        events.push(event);
281→
282→        if (event.type === "error") {
283→          const errorText = (event as { error?: string }).error;
284→          throw new Error(`SSE error event: ${errorText ?? "unknown error"}`);
285→        }
286→
287→        if (event.type === "done") {
288→          return events;
289→        }
290→      }
291→    }
292→  } finally {
293→    clearTimeout(timeout);
294→    reader.releaseLock();
295→  }
296→
297→  return events;
298→}
