 45→    const { workspaceId } = await createTestWorkspace(surreal, "skeleton-create");
 46→
 47→    // When the human creates a constraint learning: "Never use null for domain data values"
 48→    const response = await createLearningViaHttp(baseUrl, user, workspaceId, {
 49→      text: "Never use null for domain data values. Use undefined via optional properties instead.",
 50→      learning_type: "constraint",
 51→      priority: "high",
 52→      target_agents: [],
