    59→export async function updateLearningStatus(input: {
    60→  surreal: Surreal;
    61→  workspaceRecord: RecordId<"workspace", string>;
    62→  learningRecord: LearningRecord;
    63→  newStatus: LearningStatus;
    64→  now: Date;
    65→  actorRecord?: RecordId<"identity", string>;
    66→  reason?: string;
    67→}): Promise<void> {
    68→  const row = await input.surreal.select<{ workspace: RecordId<"workspace", string>; status: LearningStatus }>(input.learningRecord);
    69→  if (!row) {
    70→    throw new Error(`learning not found: ${input.learningRecord.id as string}`);
    71→  }
    72→
    73→  if ((row.workspace.id as string) !== (input.workspaceRecord.id as string)) {
    74→    throw new Error("learning is outside the current workspace scope");
    75→  }
    76→
    77→  const auditFields = buildAuditFields(input.newStatus, input.now, input.actorRecord, input.reason);
    78→
    79→  await input.surreal.update(input.learningRecord).merge({
    80→    status: input.newStatus,
    81→    updated_at: input.now,
    82→    ...auditFields,
    83→  });
    84→}
    85→
    86→function buildAuditFields(
    87→  newStatus: LearningStatus,
    88→  now: Date,
    89→  actorRecord?: RecordId<"identity", string>,
    90→  reason?: string,
    91→): Record<string, unknown> {
    92→  switch (newStatus) {
    93→    case "active":
    94→      return {
    95→        activated_at: now,
    96→        ...(actorRecord ? { approved_by: actorRecord } : {}),
    97→        approved_at: now,
    98→      };
    99→    case "dismissed":
   100→      return {
   101→        dismissed_at: now,
   102→        ...(actorRecord ? { dismissed_by: actorRecord } : {}),
   103→        ...(reason ? { dismissed_reason: reason } : {}),
   104→      };
   105→    case "deactivated":
   106→      return {
   107→        deactivated_at: now,
   108→        ...(actorRecord ? { deactivated_by: actorRecord } : {}),
   109→      };
   110→    case "superseded":
   111→      return {};
   112→    case "pending_approval":
   113→      return {};
   114→  }
   115→}
